PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "points" integer not null default '0', "bio" text, "avatar" varchar, "location" varchar, "is_admin" tinyint(1) not null default '0');
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "books" ("id" integer primary key autoincrement not null, "name" varchar not null default 'The Book With No Name', "status" varchar not null default 'in_progress', "winner_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("winner_id") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "chapters" ("id" integer primary key autoincrement not null, "book_id" integer not null, "title" varchar not null, "number" integer not null, "content" text not null, "version" varchar not null default 'A', "status" varchar not null default 'draft', "created_at" datetime, "updated_at" datetime, "is_archived" tinyint(1) not null default '0', "round_number" integer, "version_label" varchar, "is_locked" tinyint(1) not null default '0', foreign key("book_id") references "books"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "edits" ("id" integer primary key autoincrement not null, "user_id" integer not null, "chapter_id" integer not null, "type" varchar not null, "original_text" text not null, "edited_text" text not null, "status" varchar not null default 'pending', "points_awarded" integer not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "payments" ("id" integer primary key autoincrement not null, "user_id" integer not null, "amount_cents" integer not null, "payment_id" varchar, "status" varchar not null default 'pending', "edit_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("edit_id") references "edits"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "votes" ("id" integer primary key autoincrement not null, "user_id" integer not null, "chapter_id" integer not null, "version_chosen" varchar not null, "created_at" datetime, "updated_at" datetime, "round_number" integer, "version_voted" varchar, "session_id" varchar, "paid_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "feedback" ("id" integer primary key autoincrement not null, "user_id" integer, "chapter_id" integer, "content" text not null, "type" varchar not null default 'general', "email" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "reading_progress" ("id" integer primary key autoincrement not null, "user_id" integer not null, "chapter_id" integer not null, "completed" tinyint(1) not null default '0', "last_read_at" datetime, "created_at" datetime, "updated_at" datetime, "scroll_position" integer not null default '0', foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "achievements" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" varchar not null, "icon_emoji" varchar not null, "requirement_type" varchar not null, "requirement_value" integer not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "paragraph_reactions" ("id" integer primary key autoincrement not null, "user_id" integer not null, "chapter_id" integer not null, "paragraph_index" integer not null, "reaction_type" varchar not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "user_achievements" ("id" integer primary key autoincrement not null, "user_id" integer not null, "achievement_id" integer not null, "unlocked_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("achievement_id") references "achievements"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "activity_feed" ("id" integer primary key autoincrement not null, "user_id" integer not null, "activity_type" varchar not null, "description" varchar not null, "chapter_id" integer, "metadata" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "chapter_statistics" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "total_reads" integer not null default '0', "total_edits" integer not null default '0', "accepted_edits" integer not null default '0', "total_votes" integer not null default '0', "total_reactions" integer not null default '0', "average_rating" float not null default '0', "created_at" datetime, "updated_at" datetime, "rejected_edits" integer not null default '0', foreign key("chapter_id") references "chapters"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "moderation_queue" ("id" integer primary key autoincrement not null, "edit_id" integer not null, "status" varchar not null default 'pending', "reason" text, "reviewed_by" integer, "reviewed_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("edit_id") references "edits"("id") on delete cascade, foreign key("reviewed_by") references "users"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "notifications" ("id" integer primary key autoincrement not null, "user_id" integer not null, "type" varchar not null, "title" varchar not null, "message" text not null, "is_subscribed" tinyint(1) not null default '1', "read_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "inline_edits" ("id" integer primary key autoincrement not null, "chapter_id" integer not null, "user_id" integer not null, "paragraph_number" integer not null, "original_text" text not null, "suggested_text" text not null, "reason" text, "status" varchar check ("status" in ('pending', 'approved', 'rejected')) not null default 'pending', "admin_notes" text, "created_at" datetime, "updated_at" datetime, foreign key("chapter_id") references "chapters"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
DELETE FROM sqlite_sequence;
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "votes_user_id_chapter_id_unique" on "votes" ("user_id", "chapter_id");
CREATE UNIQUE INDEX "reading_progress_user_id_chapter_id_unique" on "reading_progress" ("user_id", "chapter_id");
CREATE UNIQUE INDEX "achievements_name_unique" on "achievements" ("name");
CREATE UNIQUE INDEX "paragraph_reactions_user_id_chapter_id_paragraph_index_reaction_type_unique" on "paragraph_reactions" ("user_id", "chapter_id", "paragraph_index", "reaction_type");
CREATE UNIQUE INDEX "user_achievements_user_id_achievement_id_unique" on "user_achievements" ("user_id", "achievement_id");
CREATE UNIQUE INDEX "chapter_statistics_chapter_id_unique" on "chapter_statistics" ("chapter_id");
COMMIT;
